const shapeSortConfig = {
  tileSizePx: 72,
  dragPaddingPx: 6,
  snapTolerancePx: 16,
  // Mobile-friendly: larger touch targets on small screens
  get effectiveDragPaddingPx() {
    const isTouch = window.matchMedia('(pointer: coarse)').matches;
    return isTouch ? 24 : this.dragPaddingPx;
  },
};

